案例1：循环注册点击事件
/* var lis = document.querySelector(&#39;.nav&#39;).querySelectorAll(&#39;li&#39;) for(var i = 0; i &lt; lis.length; i++) { lis[i].onclick = function() { console.log(i) } } lis[i].onclick 是异步任务，点击了之后才会去执行，但是 for 循环是同步任务，会立即执行。所以 i 永远会是 4。 */ // 利用闭包的方式得到当前 li 的索引 var lis = document.querySelector(&#39;.nav&#39;).querySelectorAll(&#39;li&#39;) for (var i = 0; i &lt; lis.length; i++) { // 利用 for 循环创建了 4 个立即执行函数 (function(j) { lis[j].onclick = function() { console.log(j) } })(i); } 案例2：循环中的 setTimeout()
